 1	import { type FC, useContext } from 'react';
 2	import { CreateOverviewContext } from 'src/overview/hooks/OverviewContext';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import LoadingSuspend from '@components/LoadingSuspend';
 6	import type { V1beta1ForkliftController } from '@kubev2v/types';
 7	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 8	
 9	import { useVmMigrationsDataPoints } from '../../hooks/useVmMigrationsDataPoints';
10	import { TimeRangeOptions } from '../../utils/timeRangeOptions';
11	import HeaderActions from '../CardHeaderActions';
12	
13	import VmMigrationsHistoryChart from './VmMigrationsHistoryChart';
14	
15	type MigrationsCardProps = {
16	  obj?: V1beta1ForkliftController;
17	  loaded?: boolean;
18	  loadError?: unknown;
19	};
20	
21	const VmMigrationsHistoryCard: FC<MigrationsCardProps> = () => {
22	  const { t } = useForkliftTranslation();
23	  const { data, setData } = useContext(CreateOverviewContext);
24	  const selectedRange = data?.vmMigrationsHistorySelectedRange ?? TimeRangeOptions.Last10Days;
25	  const setSelectedRange = (range: TimeRangeOptions) => {
26	    setData({
27	      ...data,
28	      vmMigrationsHistorySelectedRange: range,
29	    });
30	  };
31	  const { failed, loaded, loadError, obj, running, succeeded } =
32	    useVmMigrationsDataPoints(selectedRange);
33	
34	  return (
35	    <Card className="pf-m-full-height">
36	      <CardHeader
37	        actions={{
38	          actions: (
39	            <HeaderActions
40	              selectedTimeRange={selectedRange}
41	              setSelectedTimeRange={setSelectedRange}
42	            />
43	          ),
44	        }}
45	      >
46	        <CardTitle className="forklift-title">{t('Migration history')}</CardTitle>
47	      </CardHeader>
48	      <CardBody className="forklift-overview__status-migration-chart">
49	        <LoadingSuspend obj={obj} loaded={loaded} loadError={loadError}>
50	          <VmMigrationsHistoryChart
51	            selectedRange={selectedRange}
52	            vmMigrationsDataPoints={{
53	              failed,
54	              running,
55	              succeeded,
56	            }}
57	          />
58	        </LoadingSuspend>
59	      </CardBody>
60	    </Card>
61	  );
62	};
63	
64	export default VmMigrationsHistoryCard;

